Hesap makinesi - if-elif-else.code:
function hesapla(a: int, b: int, işlem: string)
    if işlem == "+":
        return a + b
    elif işlem == "-":
        return a - b
    elif işlem == "*":
        return a * b
    elif işlem == "/":
        return a / b
    else:
        return 0

print("10 + 5 = " + hesapla(10, 5, "+"))
print("10 - 5 = " + hesapla(10, 5, "-"))
print("10 * 5 = " + hesapla(10, 5, "*"))
print("10 / 5 = " + hesapla(10, 5, "/"))

Sayı analizi - karmaşık logic.code:
function sayı_analizi(sayi: int)
    string sonuç = ""
    if sayi > 0:
        sonuç = sonuç + "Pozitif "
    elif sayi < 0:
        sonuç = sonuç + "Negatif "
    else:
        sonuç = sonuç + "Sıfır "

    if sayi % 2 == 0:
        sonuç = sonuç + "Çift"
    else:
        sonuç = sonuç + "Tek"

    return sonuç

print("5: " + sayı_analizi(5))
print("8: " + sayı_analizi(8))
print("0: " + sayı_analizi(0))
print("-3: " + sayı_analizi(-3))

Fibonacci - recursive algoritma.code:
function fibonacci(n: int)
    if n <= 1:
        return n
    else:
        return fibonacci(n - 1) + fibonacci(n - 2)

print("Fibonacci(0) = " + fibonacci(0))
print("Fibonacci(1) = " + fibonacci(1))
print("Fibonacci(5) = " + fibonacci(5))
print("Fibonacci(8) = " + fibonacci(8))
